        { __m256d tr = x6_re;
          x6_re = _mm256_fmadd_pd(x6_re,_mm256_set1_pd(iw_re[42]),_mm256_mul_pd(x6_im,_mm256_set1_pd(iw_im[42])));
          x6_im = _mm256_fnmadd_pd(tr,_mm256_set1_pd(iw_im[42]),_mm256_mul_pd(x6_im,_mm256_set1_pd(iw_re[42]))); }
